parameters.jsCode:
// Valida inputs y normaliza motivo.
const d = $json;

if (!d.session_id || typeof d.session_id !== 'string') {
  throw new Error('session_id requerido');
}
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!UUID_RE.test(d.session_id)) {
  throw new Error('session_id debe ser UUID valido');
}

const MOTIVO_ENUM = new Set(['lead_solicito', 'bot_no_pudo_resolver', 'score_alto_proactivo']);
const motivo = MOTIVO_ENUM.has(d.motivo) ? d.motivo : 'lead_solicito';
const contexto = (d.contexto || '').toString().slice(0, 500);

return [{ json: {
  session_id: d.session_id,
  motivo,
  contexto,
} }];

// Construye PATCH body y payload para notificar.
const input = $('Validate Input').first().json;
const current = $json;

if (!Array.isArray(current) || current.length === 0) {
  return [{ json: {
    ok: false,
    reason: 'lead_no_existe',
    session_id: input.session_id,
    tool_output_text: 'No encontre tu registro de sesion. Por favor escribeme tu nombre, WhatsApp y correo para pasarle tus datos al equipo.',
  } }];
}

const lead = current[0];
const prevHistory = Array.isArray(lead.score_history) ? lead.score_history : [];
const prevScoreNumeric = typeof lead.score_numeric === 'number' ? lead.score_numeric : 0;
const newScoreNumeric = Math.max(prevScoreNumeric, 75);

const historyEntry = {
  at: new Date().toISOString(),
  action: 'broker_requested',
  motivo: input.motivo,
  contexto: input.contexto,
  score_numeric_before: prevScoreNumeric,
  score_numeric_after: newScoreNumeric,
};

const patchBody = {
  broker_requested_at: new Date().toISOString(),
  broker_request_reason: input.motivo,
  score: 'CALIENTE',
  score_numeric: newScoreNumeric,
  score_history: [...prevHistory, historyEntry],
};

const notifPayload = {
  lead_id: lead.id,
  session_id: input.session_id,
  score: 'CALIENTE',
  score_numeric: newScoreNumeric,
  nombre: lead.nombre,
  whatsapp: lead.whatsapp,
  email: lead.email,
  intencion: lead.intencion,
  plazo: lead.plazo,
  presupuesto: lead.presupuesto,
  uso: lead.uso,
  forma_pago: lead.forma_pago,
  rango_presupuesto: lead.rango_presupuesto,
  decisor: lead.decisor,
  pre_aprobacion: lead.pre_aprobacion,
  resumen: lead.resumen,
  motivo: input.motivo,
  contexto: input.contexto,
  broker_request: true,
};

return [{ json: {
  ok: true,
  session_id: input.session_id,
  lead_id: lead.id,
  patchBody,
  notifPayload,
  nombre: lead.nombre,
} }];

// Pasa solo el notifPayload al siguiente node (subworkflow notificar_diego).
const prev = $('Build payloads').first().json;
return [{ json: prev.notifPayload }];

const prepared = $('Build payloads').first().json;
const notif = $json;

const primerNombre = (prepared.nombre || '').split(' ')[0] || 'hola';

return [{ json: {
  ok: true,
  lead_id: prepared.lead_id,
  session_id: prepared.session_id,
  broker_notificado: !!(notif && notif.notified),
  tool_output_text: `Listo ${primerNombre}, le paso tu solicitud al equipo. Te van a contactar por WhatsApp en horario lun-vie 9-19 hrs. Si es urgente, tambien podes escribir al +56 9 4032 9987.`,
} }];

// Rama lead_no_existe: devuelve sin tocar nada.
const v = $json;
return [{ json: {
  ok: false,
  reason: v.reason,
  session_id: v.session_id,
  tool_output_text: v.tool_output_text,
} }];
